=<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<style>
  * { margin:0; padding:0; box-sizing:border-box; }
  body { background:#09090b; font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif; }
  .wrap { max-width:580px; margin:32px auto; background:#18181b; border-radius:16px; overflow:hidden; border:1px solid #27272a; }
  .hero { background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%); padding:36px 32px; }
  .hero-badge { display:inline-block; background:rgba(0,0,0,.18); color:#000; font-size:11px; font-weight:700; letter-spacing:.08em; text-transform:uppercase; padding:4px 10px; border-radius:20px; margin-bottom:12px; }
  .hero h1 { font-size:26px; font-weight:800; color:#000; line-height:1.2; }
  .hero p { color:rgba(0,0,0,.6); font-size:13px; margin-top:6px; }
  .body { padding:28px 32px; }
  .card { background:#09090b; border:1px solid #27272a; border-radius:12px; padding:20px; margin-bottom:20px; }
  .card-title { font-size:18px; font-weight:700; color:#fafafa; margin-bottom:16px; line-height:1.3; }
  .fields { display:grid; grid-template-columns:1fr 1fr; gap:14px; }
  .field { background:#18181b; border-radius:8px; padding:12px 14px; }
  .field-label { font-size:10px; font-weight:700; color:#71717a; text-transform:uppercase; letter-spacing:.08em; margin-bottom:5px; }
  .field-value { font-size:14px; color:#e4e4e7; font-weight:500; }
  .badge { display:inline-block; padding:3px 10px; border-radius:20px; font-size:12px; font-weight:600; }
  .badge-amber { background:rgba(245,158,11,.15); color:#f59e0b; }
  .badge-blue  { background:rgba(59,130,246,.15);  color:#3b82f6; }
  .badge-green { background:rgba(34,197,94,.15);   color:#22c55e; }
  .badge-red   { background:rgba(239,68,68,.15);   color:#ef4444; }
  .badge-gray  { background:rgba(113,113,122,.15); color:#a1a1aa; }
  .desc { background:#09090b; border-left:3px solid #f59e0b; border-radius:0 8px 8px 0; padding:12px 16px; margin-bottom:20px; color:#a1a1aa; font-size:13px; line-height:1.6; }
  .cta { text-align:center; padding:4px 0 8px; }
  .btn { display:inline-block; background:#f59e0b; color:#000 !important; font-weight:700; font-size:14px; padding:14px 32px; border-radius:10px; text-decoration:none; letter-spacing:.01em; }
  .footer { padding:20px 32px; text-align:center; border-top:1px solid #27272a; }
  .footer p { font-size:11px; color:#52525b; line-height:1.7; }
  .logo { font-size:13px; font-weight:700; color:#f59e0b; margin-bottom:4px; }
  @media(max-width:540px){ .fields{grid-template-columns:1fr} .body{padding:20px} .hero{padding:24px 20px} }
</style>
</head>
<body>
<div class="wrap">

  <div class="hero">
    <div class="hero-badge">JUS IA · Notificação</div>
    <h1>{{ $json.tipo_label }}</h1>
    <p>{{ $json.tipo_notificacao === 'criada' ? 'Uma nova missão foi criada no sistema' : $json.tipo_notificacao === 'status_mudou' ? 'O status da missão foi atualizado' : 'O prazo desta missão está se aproximando' }}</p>
  </div>

  <div class="body">

    <div class="card">
      <div class="card-title">{{ $json.titulo }}</div>

      <div class="fields">
        <div class="field">
          <div class="field-label">Responsável</div>
          <div class="field-value">{{ $json.responsavel }}</div>
        </div>
        <div class="field">
          <div class="field-label">Status</div>
          <div class="field-value"><span class="badge badge-amber">{{ $json.status }}</span></div>
        </div>
        <div class="field">
          <div class="field-label">Prioridade</div>
          <div class="field-value"><span class="badge {{ $json.prioridade === 'Alta' || $json.prioridade === 'Crítica' ? 'badge-red' : $json.prioridade === 'Normal' ? 'badge-blue' : 'badge-gray' }}">{{ $json.prioridade }}</span></div>
        </div>
        <div class="field">
          <div class="field-label">Vencimento</div>
          <div class="field-value">{{ $json.data_vencimento }}</div>
        </div>
      </div>
    </div>

    {{ $json.descricao && $json.descricao !== '—' ? '<div class="desc"><strong style="color:#e4e4e7;font-size:11px;text-transform:uppercase;letter-spacing:.06em">Descrição</strong><br><br>' + $json.descricao + '</div>' : '' }}

    <div class="cta">
      <a href="{{ $json.link_tarefa }}" class="btn">Ver Missão no JUS IA →</a>
    </div>

  </div>

  <div class="footer">
    <div class="logo">VG AI – Gestão Jurídica</div>
    <p>Notificação automática · Não responda este email<br>© 2026 JUS IA · Todos os direitos reservados</p>
  </div>

</div>
</body>
</html>
